def _wait_for_boot_snapshot(self, session: FirmwareSession) -> list[str]:
    deadline = time.monotonic() + 4.0
    lines: list[str] = []
    while time.monotonic() < deadline:
        lines.extend(session.read_lines(timeout_s=0.2))
        if (
            "DBG BOOTED" in lines
            and "ACT COMPRESSOR OFF" in lines
            and "ACT VENT OPEN" in lines
            and "DBG STATE SAFE_VENT" in lines
        ):
            return lines
    raise TimeoutError("boot snapshot was not observed within 4.0 s")

